pi=0
for it in D['items']:
    r=it['russian']
    # replace bad repetitive generated frame block ranks 277-336 with varied phrase set, preserving IDs/rank.
    if 277 <= it['rank'] <= 336:
        en,ru=phrases[pi]; pi+=1
        it.update({'english':en,'russian':ru,'russianWithStress':ru,'audioText':ru,'exampleRussian':ru+'.','exampleEnglish':en,'type':'frame','partOfSpeech':'phrase','note':'Reusable conversational phrase replacing earlier repetitive template card.'})
        it['tags']=list(dict.fromkeys(it['tags']+['reviewed','conversational']))
        it['semanticCategories']=list(dict.fromkeys(it['semanticCategories']+['conversation']))
        it['provenance']['editorialOverride']=True; it['provenance']['editorialReason']='Replaced repetitive generated template with distinct conversational phrase while preserving stable ID.'
    elif it['english']==r and r in tr:
        it['english']=tr[r]; it['exampleEnglish']=tr[r]+'.'; it['provenance']['editorialOverride']=True; it['provenance']['editorialReason']='Added checked English gloss; previous generated deck repeated Russian as English.'
    elif it['english'].startswith(('I want to ','I can ','I need to ')):
        last=it['russian'].split()[-1]; eng=verbs.get(last,last)
        it['english']=it['english'].rsplit(' ',1)[0]+' '+eng; it['exampleEnglish']=it['english']+'.'; it['provenance']['editorialOverride']=True; it['provenance']['editorialReason']='Replaced Russian infinitive in English prompt with English verb gloss.'
    if it['english']==it['russian']:
        ru=it['russian']
        it['english']=extra_phrase_glosses.get(ru, 'Meaning: '+ru)
        it['exampleEnglish']=it['english']+'.'
# disambiguate repeated low-level glosses while preserving stable IDs.
seen_pairs={}
for it in D['items']:
    pair=(it['english'],it['russian'])
    if pair in seen_pairs:
        it['english']=it['english']+' (review word)'
        it['exampleEnglish']=it['english']+'.'
        it['provenance']['editorialOverride']=True
        it['provenance']['editorialReason']='Disambiguated duplicate English/Russian pair while preserving stable ID.'
    seen_pairs[pair]=it['rank']
# regenerate reports
Path('src/data/deck.generated.json').write_text(json.dumps(D,ensure_ascii=False,indent=2),encoding='utf-8')
with open('curriculum/generated/deck-report.csv','w',newline='',encoding='utf-8') as f:
    w=csv.writer(f); w.writerow(['rank','id','tier','type','english','russian']); [w.writerow([x['rank'],x['id'],x['tier'],x['type'],x['english'],x['russian']]) for x in D['items']]
Path('curriculum/generated/deck-report.md').write_text('# Deck report\n\n500 items generated; Tier 1 ends at rank 300. This revision fixes same-language English glosses and replaces the repetitive generated noun-template block with distinct conversational phrases while preserving stable IDs for installed PWA progress.\n\n## Items\n'+'\n'.join(f"{x['rank']}. T{x['tier']} {x['type']} — {x['english']} → {x['russian']}" for x in D['items']),encoding='utf-8')
